CREATE TABLE IF NOT EXISTS "SaasPlan" ("id" TEXT NOT NULL PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"price" DECIMAL(12,2) NOT NULL,"currency" TEXT NOT NULL DEFAULT 'SAR',"billingCycle" TEXT NOT NULL DEFAULT 'MONTHLY',"quotas" JSONB NOT NULL,"features" JSONB NOT NULL,"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SaasSubscription" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"planId" TEXT NOT NULL REFERENCES "SaasPlan"("id") ON DELETE RESTRICT ON UPDATE CASCADE,"status" TEXT NOT NULL DEFAULT 'TRIAL',"trialEndsAt" TIMESTAMP(3),"startsAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"endsAt" TIMESTAMP(3),"licenses" INTEGER NOT NULL DEFAULT 1,"usage" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SaasInvoice" ("id" TEXT NOT NULL PRIMARY KEY,"subscriptionId" TEXT NOT NULL REFERENCES "SaasSubscription"("id") ON DELETE CASCADE ON UPDATE CASCADE,"invoiceNumber" TEXT NOT NULL UNIQUE,"amount" DECIMAL(12,2) NOT NULL,"currency" TEXT NOT NULL DEFAULT 'SAR',"status" TEXT NOT NULL DEFAULT 'OPEN',"dueAt" TIMESTAMP(3),"paidAt" TIMESTAMP(3),"lineItems" JSONB NOT NULL,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SaasPayment" ("id" TEXT NOT NULL PRIMARY KEY,"invoiceId" TEXT NOT NULL REFERENCES "SaasInvoice"("id") ON DELETE CASCADE ON UPDATE CASCADE,"provider" TEXT NOT NULL,"reference" TEXT,"amount" DECIMAL(12,2) NOT NULL,"currency" TEXT NOT NULL DEFAULT 'SAR',"status" TEXT NOT NULL DEFAULT 'PENDING',"payload" JSONB,"paidAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SaasCoupon" ("id" TEXT NOT NULL PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"type" TEXT NOT NULL,"value" DECIMAL(12,2) NOT NULL,"maxRedemptions" INTEGER,"redeemed" INTEGER NOT NULL DEFAULT 0,"expiresAt" TIMESTAMP(3),"isActive" BOOLEAN NOT NULL DEFAULT true,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SaasUsageRecord" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"metric" TEXT NOT NULL,"quantity" DOUBLE PRECISION NOT NULL,"unit" TEXT NOT NULL,"period" TEXT NOT NULL,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SaasLicense" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"key" TEXT NOT NULL UNIQUE,"product" TEXT NOT NULL,"seats" INTEGER NOT NULL,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"expiresAt" TIMESTAMP(3),"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "SaasPlatformRecord" ("id" TEXT NOT NULL PRIMARY KEY,"tenantId" TEXT,"suite" TEXT NOT NULL,"feature" TEXT NOT NULL,"code" TEXT NOT NULL,"name" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"payload" JSONB NOT NULL,"metrics" JSONB,"createdById" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("tenantId","suite","feature","code"));
CREATE TABLE IF NOT EXISTS "DeploymentCenterRecord" ("id" TEXT NOT NULL PRIMARY KEY,"environment" TEXT NOT NULL,"releaseVersion" TEXT NOT NULL,"channel" TEXT NOT NULL,"strategy" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'PENDING',"commitSha" TEXT,"artifactUrl" TEXT,"rollbackTo" TEXT,"featureFlags" JSONB,"startedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"finishedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "BackupCenterRecord" ("id" TEXT NOT NULL PRIMARY KEY,"type" TEXT NOT NULL,"provider" TEXT NOT NULL,"location" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'PENDING',"sizeBytes" INTEGER,"checksum" TEXT,"scheduledAt" TIMESTAMP(3),"completedAt" TIMESTAMP(3),"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "DisasterRecoveryRecord" ("id" TEXT NOT NULL PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"rpoMinutes" INTEGER NOT NULL,"rtoMinutes" INTEGER NOT NULL,"replication" JSONB NOT NULL,"failover" JSONB NOT NULL,"status" TEXT NOT NULL DEFAULT 'READY',"lastTestAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ObservabilityRecord" ("id" TEXT NOT NULL PRIMARY KEY,"type" TEXT NOT NULL,"source" TEXT NOT NULL,"severity" TEXT NOT NULL DEFAULT 'INFO',"message" TEXT NOT NULL,"traceId" TEXT,"spanId" TEXT,"metricValue" DOUBLE PRECISION,"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "ComplianceControl" ("id" TEXT NOT NULL PRIMARY KEY,"framework" TEXT NOT NULL,"controlCode" TEXT NOT NULL,"title" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'IN_REVIEW',"evidence" JSONB,"ownerUserId" TEXT,"dueAt" TIMESTAMP(3),"reviewedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("framework","controlCode"));
CREATE TABLE IF NOT EXISTS "LocalizationRecord" ("id" TEXT NOT NULL PRIMARY KEY,"locale" TEXT NOT NULL,"namespace" TEXT NOT NULL,"key" TEXT NOT NULL,"value" TEXT NOT NULL,"direction" TEXT NOT NULL DEFAULT 'RTL',"currency" TEXT,"timezone" TEXT,"calendar" TEXT,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,UNIQUE("locale","namespace","key"));
CREATE TABLE IF NOT EXISTS "MobilePlatformRecord" ("id" TEXT NOT NULL PRIMARY KEY,"userId" TEXT,"deviceId" TEXT NOT NULL UNIQUE,"platform" TEXT NOT NULL,"pushToken" TEXT,"biometricEnabled" BOOLEAN NOT NULL DEFAULT false,"offlineCursor" TEXT,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"lastSyncAt" TIMESTAMP(3),"metadata" JSONB,"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "DataWarehouseRecord" ("id" TEXT NOT NULL PRIMARY KEY,"pipeline" TEXT NOT NULL,"layer" TEXT NOT NULL,"dataset" TEXT NOT NULL,"partition" TEXT,"status" TEXT NOT NULL DEFAULT 'READY',"rowsCount" INTEGER NOT NULL DEFAULT 0,"schemaJson" JSONB NOT NULL,"metrics" JSONB,"loadedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "AutomationRecord" ("id" TEXT NOT NULL PRIMARY KEY,"code" TEXT NOT NULL UNIQUE,"name" TEXT NOT NULL,"triggerType" TEXT NOT NULL,"bpmn" JSONB,"nodes" JSONB NOT NULL,"edges" JSONB NOT NULL,"status" TEXT NOT NULL DEFAULT 'ACTIVE',"lastRunAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "QualityRecord" ("id" TEXT NOT NULL PRIMARY KEY,"suite" TEXT NOT NULL,"testType" TEXT NOT NULL,"name" TEXT NOT NULL,"status" TEXT NOT NULL DEFAULT 'PENDING',"result" JSONB,"durationMs" INTEGER,"executedAt" TIMESTAMP(3),"createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
